const q = $('Webhook').first().json.query || {};
const match_pair_id = String(q.match_pair_id || '').trim();
const since = q.since ? Date.parse(q.since) : 0;
if (!match_pair_id) throw new Error('match_pair_id required');

const allRows = $input.all().map(i => i.json);

// Determine which upstream read this item came from by shape:
// chat_messages rows have 'Match Pair Id'; user_vectors rows have 'session_id'.
const msgRows   = allRows.filter(r => 'Match Pair Id' in r);
const userRows  = allRows.filter(r => 'session_id' in r && !('Match Pair Id' in r));

const mapped = msgRows
  .filter(r => String(r['Match Pair Id']) === match_pair_id)
  .map(r => ({
    message_id: r['Message Id'],
    match_pair_id: r['Match Pair Id'],
    from_session_id: r['From Session Id'],
    text: r['Text'],
    timestamp: r['Timestamp']
  }))
  .filter(m => {
    // drop legacy system leak rows that may still sit in chat_messages
    if (m.from_session_id === 'system') return false;
    if (m.text === '__partner_left__' || m.text === '__chat_timeout__') return false;
    const ts = m.timestamp ? Date.parse(m.timestamp) : 0;
    return ts > since;
  });
mapped.sort((a, b) => Date.parse(a.timestamp) - Date.parse(b.timestamp));

// Pair status derived from user_vectors match_ended_at on either side.
const pairSids = match_pair_id.split('__');
let pair_status = 'active';
let ended_at = '';
for (const u of userRows) {
  if (!pairSids.includes(String(u.session_id))) continue;
  const ea = String(u.match_ended_at || '').trim();
  if (ea) { pair_status = 'ended'; ended_at = ea; break; }
}

return [{ json: { messages: mapped, pair_status, ended_at } }];
